  {

    if digits[i] == 8 {
      cnt8 := cnt8 + 1;
    }
  }

  CountOccurrencesNonNeg(digits, 8);
  if cnt8 < n / 11 {
    count := cnt8;
  } else {
    count := n / 11;
  }
}

